  ],
  "properties": {
    "complaintId": {
      "type": "string",
      "description": "The ComplaintId of the case to summarise (e.g. CMP-2026-...). Used to look up the record in the ComplaintsData Data Fabric context."
    }
  }
}

spec.outputArgumentsSchemaV2:
{
  "type": "object",
  "properties": {
    "emailSubject": {
      "type": "string",
      "description": "Concise subject line for the customer email, including the ComplaintId."
    },
    "emailHtml": {
      "type": "string",
      "description": "The full customer case-update email body as valid, self-contained HTML (no html/head/body wrapper, no external CSS or images)."
    },
    "recipientEmail": {
      "type": "string",
      "description": "The customer's email address taken from the record's Sender if it is an address, else empty string."
    }
  }
}

